#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int H, N, M, A, B, IND;
        scanf("%d %d %d %d %d", &H, &N, &M, &A, &B, &IND);
        int D[M];
        for (int i = 0; i < M; i++) {
            scanf("%d", &D[i]);
        }
        double area = 0;
        int X = 0;
        for (int i = 1; i < N; i++) {
            int newX = X + D[IND];
            IND = (A * IND + B) % M;
            double base = newX - X;
            double height = (i % 2 == 1) ? H : 0;
            area += 0.5 * base * height;
            X = newX;
        }
        printf("%.1f\n", area);
    }
    return 0;
}

